#include <stdio.h>
#define MOD 1000000007

int fib(int n) {
    if (n <= 1) return n;
    int a = 0, b = 1;
    for (int i = 2; i <= n; i++) {
        int temp = (a + b) % MOD;
        a = b;
        b = temp;
    }
    return b;
}

int countOnes(int n) {
    int count = 0;
    while (n) {
        count += n & 1;
        n >>= 1;
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, G;
        scanf("%d %d", &N, &G);
        int ways = fib(N + 1);
        int ones = countOnes(ways);
        if (ones == G) printf("CORRECT\n");
        else printf("INCORRECT\n");
    }
    return 0;
}

